// Lee explícitamente del Webhook inicial usando la sintaxis de n8n v1+
const webhookData = $('WhatsApp Webhook POST').item.json;
const body = webhookData.body || webhookData;

const value = body?.entry?.[0]?.changes?.[0]?.value || {};
const message = value?.messages?.[0] || null;
const contact = value?.contacts?.[0] || {};
const status = value?.statuses?.[0] || null;

if (status && !message) {
  return [{
    json: {
      is_valid_message: false,
      event_type: 'status',
      reason: 'WhatsApp status event ignored',
      status_id: status.id || null,
      status_value: status.status || null,
      raw: body
    }
  }];
}

if (!message) {
  return [{
    json: {
      is_valid_message: false,
      event_type: 'unknown',
      reason: 'No message object found',
      raw: body
    }
  }];
}

const type = message.type;
let text = '';
let media_id = null;

if (type === 'text') {
  text = message?.text?.body || '';
}

if (type === 'audio') {
  media_id = message?.audio?.id || null;
}

if (type === 'image') {
  text = message?.image?.caption || '';
  media_id = message?.image?.id || null;
}

if (type === 'document') {
  text = message?.document?.caption || '';
  media_id = message?.document?.id || null;
}

return [{
  json: {
    is_valid_message: true,
    event_type: 'message',
    from: message.from,
    customer_name: contact?.profile?.name || null,
    message_id: message.id,
    message_type: type,
    text,
    media_id,
    timestamp: message.timestamp,
    session_id: message.from,
    business_phone_number_id: value?.metadata?.phone_number_id || null,
    display_phone_number: value?.metadata?.display_phone_number || null,
    raw_message: message
  }
}];

const input = $json;

let reply = input.output || input.reply || input.text || '';

if (!reply) {
  reply = 'Gracias por escribirnos. ¿En qué puedo ayudarte?';
}

if (reply.length > 3500) {
  reply = reply.slice(0, 3400) + '\n\nTe resumo lo principal arriba. Si deseas, te puedo dar más detalle.';
}

// Strip markdown images entirely: ![Name](URL)
reply = reply.replace(/!\[.*?\]\(.*?\)/g, '');

// Format standard markdown links [Text](URL) to "Text (URL)"
reply = reply.replace(/\[(.*?)\]\((.*?)\)/g, '$1 ($2)');

reply = reply
  .replace(/\*\*/g, '*')
  .replace(/#{1,6}\s/g, '')
  .trim();

let from = input.from || input.customer_phone || input.phone || '';

try {
  const normalize = $('Normalize WhatsApp Message').first().json;
  from = from || normalize.from || normalize.customer_phone || normalize.phone || '';
} catch (error) {
  // Safe fallback
}

return [
  {
    json: {
      from,
      reply
    }
  }
];

