const MONTHS_ES = {
  'enero':1,'febrero':2,'marzo':3,'abril':4,'mayo':5,'junio':6,
  'julio':7,'agosto':8,'septiembre':9,'octubre':10,'noviembre':11,'diciembre':12
};

function parseTimeAM(timeStr) {
  const m = timeStr.match(/(\d+):(\d+)\s*(AM|PM)/i);
  if (!m) return null;
  let h = parseInt(m[1]);
  const min = parseInt(m[2]);
  const period = m[3].toUpperCase();
  if (period === 'PM' && h !== 12) h += 12;
  if (period === 'AM' && h === 12) h = 0;
  return h * 60 + min;
}

function todaySpanish() {
  const months = ['enero','febrero','marzo','abril','mayo','junio',
                  'julio','agosto','septiembre','octubre','noviembre','diciembre'];
  const now = new Date();
  return now.getDate() + ' de ' + months[now.getMonth()] + ' de ' + now.getFullYear();
}

const now = new Date();
const nowMinutes = now.getHours() * 60 + now.getMinutes();
const todayStr = todaySpanish();

const leads = $input.all().map(item => item.json);
const result = [];

for (const lead of leads) {
  if (!lead.appointment_date || !lead.appointment_time) continue;
  if (lead.appointment_date !== todayStr) continue;

  const apptMinutes = parseTimeAM(lead.appointment_time);
  if (apptMinutes === null) continue;

  const diff = apptMinutes - nowMinutes;

  if (diff >= 55 && diff <= 65 && !lead.reminder_60_sent) {
    result.push({ json: { ...lead, reminder_type: '60min' } });
  }
  if (diff >= 5 && diff <= 15 && !lead.reminder_10_sent) {
    result.push({ json: { ...lead, reminder_type: '10min' } });
  }
}

return result;

